        restrictions[k].0 - 1 <= idx < restrictions[k].1 ==> v <= restrictions[k].2)
    ensures v <= EffectiveCap(idx, h, restrictions)
  {
    EffectiveCapTightest(idx, h, restrictions, v);
  }
}
